"use client";

import Link from "next/link";
import { FormEvent, startTransition, useEffect, useMemo, useRef, useState } from "react";
import { useRouter } from "next/navigation";

import { createProject, generateProjectSetup } from "@/lib/api";
import { PERSONA_FIELDS } from "@/lib/persona";
import type { SetupSection } from "@/lib/types";
import {
  buildWorkspaceProjectPayload,
  clearWorkspaceSetupDraft,
  consumeWorkspaceSetupNotice,
  createEmptyWorkspaceSetupDraft,
  getEarliestBlockedWorkspaceSetupStep,
  getNextWorkspaceSetupStep,
  getPreviousWorkspaceSetupStep,
  getWorkspaceSetupProgressIndex,
  getWorkspaceSetupStep,
  loadWorkspaceSetupDraft,
  saveWorkspaceSetupDraft,
  validateWorkspaceSetupStart,
  validateWorkspaceSetupStep,
  WORKSPACE_SETUP_CORRUPTION_NOTICE,
  type WorkspaceSetupStepSlug,
  WORKSPACE_SETUP_STEPS,
} from "@/lib/workspace-setup";

function getStepRoute(step: WorkspaceSetupStepSlug | null): string {
  if (!step || step === "start") {
    return "/projects/new";
  }
  return `/projects/new/${step}`;
}

function buildCurrentDraftPayload(draft: ReturnType<typeof createEmptyWorkspaceSetupDraft>) {
  const payload = {} as Record<SetupSection, string>;
  for (const field of PERSONA_FIELDS) {
    payload[field.key] = draft[field.key];
  }
  return payload;
}

function getSubmitLabel(submitting: boolean, hasNextStep: boolean) {
  if (submitting) {
    return "Creating project…";
  }
  return hasNextStep ? "Continue" : "Create project";
}

function getStartLede(userName: string) {
  return `${userName}, set the title and goal first. Data Spa will draft the persona fields one step at a time after that.`;
}

export function WorkspaceSetupClient({
  step,
  userName,
}: {
  step: WorkspaceSetupStepSlug;
  userName: string;
}) {
  const router = useRouter();
  const generationRequestIdRef = useRef(0);
  const autoGeneratedStepRef = useRef<SetupSection | null>(null);
  const [draft, setDraft] = useState(createEmptyWorkspaceSetupDraft);
  const [ready, setReady] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);
  const [generatingSection, setGeneratingSection] = useState<SetupSection | null>(null);
  const [submitting, setSubmitting] = useState(false);

  const activeStep = useMemo(() => (step === "start" ? null : getWorkspaceSetupStep(step)), [step]);
  const stepNumber = getWorkspaceSetupProgressIndex(step);
  const totalSteps = WORKSPACE_SETUP_STEPS.length + 1;

  useEffect(() => {
    const loadResult = loadWorkspaceSetupDraft();
    const stored = loadResult.draft;
    const notice = step === "start" ? consumeWorkspaceSetupNotice() ?? loadResult.notice : loadResult.notice;
    const hydrated = { ...createEmptyWorkspaceSetupDraft(), ...(stored ?? {}) };

    if (step === "start") {
      setDraft(hydrated);
      setWarning(notice);
      setReady(true);
      return;
    }

    if (!stored) {
      startTransition(() => {
        router.replace("/projects/new");
      });
      return;
    }

    const blockedStep = getEarliestBlockedWorkspaceSetupStep(hydrated, step);
    if (blockedStep) {
      startTransition(() => {
        router.replace(getStepRoute(blockedStep));
      });
      return;
    }

    setDraft(hydrated);
    setReady(true);
  }, [router, step]);

  useEffect(() => {
    setError(null);
    setWarning((current) => (current === WORKSPACE_SETUP_CORRUPTION_NOTICE ? current : null));
  }, [step]);

  useEffect(() => {
    if (!ready) {
      return;
    }
    saveWorkspaceSetupDraft(draft);
  }, [draft, ready]);

  useEffect(() => {
    if (
      !ready ||
      !activeStep ||
      draft[activeStep.section].trim() ||
      generatingSection === activeStep.section ||
      autoGeneratedStepRef.current === activeStep.section
    ) {
      return;
    }
    autoGeneratedStepRef.current = activeStep.section;
    void handleGenerate(activeStep.section);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeStep, draft, generatingSection, ready]);

  function updateDraft<K extends keyof typeof draft>(field: K, value: (typeof draft)[K]) {
    setDraft((current) => ({ ...current, [field]: value }));
    if (field !== "name" && field !== "goal") {
      setWarning(null);
    }
  }

  async function handleGenerate(section: SetupSection) {
    const startError = validateWorkspaceSetupStart(draft);
    if (startError) {
      setError(startError);
      return;
    }

    const requestId = generationRequestIdRef.current + 1;
    generationRequestIdRef.current = requestId;
    const snapshot = draft[section];

    setGeneratingSection(section);
    setError(null);
    setWarning(null);

    try {
      const response = await generateProjectSetup({
        name: draft.name.trim(),
        goal: draft.goal.trim(),
        section,
        current_draft: buildCurrentDraftPayload(draft),
      });

      if (generationRequestIdRef.current !== requestId) {
        return;
      }

      let applied = false;
      setDraft((current) => {
        if (current[section] !== snapshot) {
          return current;
        }
        applied = true;
        return { ...current, [section]: response.text };
      });

      setWarning(
        applied
          ? response.warning
          : "You edited this field before the draft finished, so your text was kept."
      );
    } catch (reason) {
      setWarning(null);
      setError(reason instanceof Error ? reason.message : "Unable to generate setup draft");
    } finally {
      if (generationRequestIdRef.current === requestId) {
        setGeneratingSection(null);
      }
    }
  }

  function handleStartSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const nextDraft = {
      ...draft,
      name: draft.name.trim(),
      goal: draft.goal.trim(),
    };
    const validationError = validateWorkspaceSetupStart(nextDraft);
    if (validationError) {
      setError(validationError);
      return;
    }

    setDraft(nextDraft);
    saveWorkspaceSetupDraft(nextDraft);
    setError(null);
    setWarning(null);
    startTransition(() => {
      router.push(getStepRoute(WORKSPACE_SETUP_STEPS[0]?.slug ?? null));
    });
  }

  async function handleStepSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    if (!activeStep) {
      return;
    }

    const validationError = validateWorkspaceSetupStep(draft, activeStep.section);
    if (validationError) {
      setError(validationError);
      return;
    }

    setError(null);
    setWarning(null);
    const nextStep = getNextWorkspaceSetupStep(activeStep.slug);
    if (nextStep) {
      startTransition(() => {
        router.push(getStepRoute(nextStep));
      });
      return;
    }

    setSubmitting(true);
    try {
      const project = await createProject(buildWorkspaceProjectPayload(draft));
      clearWorkspaceSetupDraft();
      startTransition(() => {
        router.push(`/projects/${project.id}`);
        router.refresh();
      });
    } catch (reason) {
      setError(reason instanceof Error ? reason.message : "Unable to create project");
    } finally {
      setSubmitting(false);
    }
  }

  if (!ready) {
    return (
      <section className="panel stack compact-panel">
        <p className="eyebrow">Project setup</p>
        <h1>Loading setup…</h1>
      </section>
    );
  }

  return (
    <div className="setup-grid">
      <section className="panel panel-heavy setup-panel">
        <div className="setup-header stack">
          <div className="progress-row">
            <p className="eyebrow">Guided project setup</p>
            <span className="progress-pill">
              Step {stepNumber} of {totalSteps}
            </span>
          </div>
          <h1>{step === "start" ? "Start with name and goal." : activeStep?.title}</h1>
          <p className="lede">
            {step === "start" ? getStartLede(userName) : activeStep?.description}
          </p>
        </div>

        {step === "start" ? (
          <form className="stack" onSubmit={handleStartSubmit}>
            <label className="field">
              <span>Project title</span>
              <input
                minLength={2}
                onChange={(event) => updateDraft("name", event.target.value)}
                placeholder="Founder, coach, host, strategist"
                required
                value={draft.name}
              />
            </label>
            <label className="field">
              <span>Goal</span>
              <textarea
                minLength={4}
                onChange={(event) => updateDraft("goal", event.target.value)}
                placeholder="Describe what the project should train toward and what makes the voice useful."
                required
                rows={6}
                value={draft.goal}
              />
            </label>
            {error ? <p className="error">{error}</p> : null}
            <div className="inline-actions">
              <button className="primary" type="submit">
                Continue
              </button>
              <Link className="secondary text-link" href="/">
                Cancel
              </Link>
            </div>
          </form>
        ) : (
          <form className="stack" onSubmit={handleStepSubmit}>
            <label className="field">
              <span className="field-header">
                <span>{activeStep?.label}</span>
                <button
                  className="secondary small-button"
                  disabled={generatingSection === activeStep?.section}
                  onClick={() => void handleGenerate(activeStep!.section)}
                  type="button"
                >
                  {generatingSection === activeStep?.section ? "Generating…" : "Regenerate"}
                </button>
              </span>
              <textarea
                onChange={(event) => updateDraft(activeStep!.section, event.target.value)}
                rows={activeStep?.rows}
                value={draft[activeStep!.section]}
              />
            </label>
            {warning ? <p className="muted">{warning}</p> : null}
            {error ? <p className="error">{error}</p> : null}
            <div className="inline-actions">
              <button className="primary" disabled={submitting} type="submit">
                {getSubmitLabel(submitting, Boolean(getNextWorkspaceSetupStep(activeStep!.slug)))}
              </button>
              <Link className="secondary text-link" href={getStepRoute(getPreviousWorkspaceSetupStep(step))}>
                Back
              </Link>
            </div>
          </form>
        )}
      </section>

      <aside className="panel stack setup-sidebar">
        <div className="section-header">
          <h2>Setup map</h2>
          <p>Each step keeps one decision in focus. The AI drafts first, then the operator edits if needed.</p>
        </div>
        <div className="setup-summary">
          <div className="summary-chip">
            <span>Name</span>
            <strong>{draft.name || "Not set yet"}</strong>
          </div>
          <div className="summary-chip">
            <span>Goal</span>
            <strong>{draft.goal ? "Captured" : "Waiting"}</strong>
          </div>
        </div>
        <div className="step-list">
          <div className={`step-chip ${step === "start" ? "step-chip-active" : ""}`}>
            <strong>Start</strong>
            <span>Name and goal</span>
          </div>
          {WORKSPACE_SETUP_STEPS.map((candidate) => (
            <div
              className={`step-chip ${step === candidate.slug ? "step-chip-active" : ""}`}
              key={candidate.slug}
            >
              <strong>{candidate.label}</strong>
              <span>{draft[candidate.section].trim() ? "Draft ready" : "Queued"}</span>
            </div>
          ))}
        </div>
      </aside>
    </div>
  );
}
